#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=8e4+5;
int f[maxn],ans;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	stack<int> sta;
	for(int i=1,a,b; i<=n; i++) {
		cin>>a>>b;
		while(!sta.empty()&&sta.top()>=b) {
			if(sta.top()!=b){
				ans++;
			}
			sta.pop();
		}
		sta.push(b);
	}
	cout<<ans+sta.size();
	return 0;
}
